import { cn } from '@/utils/shadcn-ui.util';
import { MoreVertical } from 'lucide-react';
import React, { ReactNode } from 'react';
import { Button } from '../shadcn-ui/button';
import { DropdownMenu, DropdownMenuContent, DropdownMenuTrigger } from '../shadcn-ui/dropdown-menu';

/** Props interface for the ResultsCard base component */
export interface ResultsCardProps {
  /** Unique key for the card */
  cardKey: string;
  /** Whether this card is currently selected/focused */
  isSelected: boolean;
  /** Callback function called when the card is clicked */
  onSelect: () => void;
  /** Whether the content of this card are in a denied state */
  isDenied?: boolean;
  /** Whether the card should be hidden */
  isHidden?: boolean;
  /** Additional CSS classes to apply to the card */
  className?: string;
  /** Main content to display on the card */
  children: ReactNode;
  /** Additional buttons to show to the end of the card when selected, before the dropdown menu */
  selectedButtons?: ReactNode;
  /** Additional buttons to show when the card is hovered but not selected */
  hoverButtons?: ReactNode;
  /** Content to show in the dropdown menu when selected */
  dropdownContent?: ReactNode;
  /** Whether to show the dropdown menu button on hover even when not selected. Defaults to false */
  showDropdownOnHover?: boolean;
  /** Additional content to show below the main content */
  additionalContent?: ReactNode;
  /** Color to use for the card's accent border */
  accentColor?: string;
}

/**
 * ResultsCard is a base component for displaying scripture-related results in a card format, even
 * though it is not based on the Card component. It provides common functionality like selection
 * state, dropdown menus, and expandable content.
 */
export function ResultsCard({
  cardKey,
  isSelected,
  onSelect,
  isDenied,
  isHidden = false,
  className,
  children,
  selectedButtons,
  hoverButtons,
  dropdownContent,
  additionalContent,
  accentColor,
  showDropdownOnHover = false,
}: ResultsCardProps) {
  const handleKeyDown = (event: React.KeyboardEvent) => {
    if (event.key === 'Enter' || event.key === ' ') {
      // Only handle keyboard activation on the card itself, not on focusable children
      // (e.g. buttons inside the card). Child elements handle their own keyboard events.
      if (event.target !== event.currentTarget) return;
      event.preventDefault();
      onSelect();
    }
  };

  return (
    <div
      hidden={isHidden}
      key={cardKey}
      onClick={onSelect}
      onKeyDown={handleKeyDown}
      role="button"
      tabIndex={0}
      aria-pressed={isSelected}
      className={cn(
        'tw-group tw-relative tw-min-w-36 tw-rounded-xl tw-border tw-shadow-none hover:tw-bg-muted/50',
        { 'tw-opacity-50 hover:tw-opacity-100': isDenied && !isSelected },
        { 'tw-bg-accent': isSelected },
        { 'tw-bg-transparent': !isSelected },
        className,
      )}
    >
      <div className="tw-flex tw-flex-col tw-gap-2 tw-p-4">
        <div className="tw-flex tw-justify-between tw-overflow-hidden">
          <div className="tw-min-w-0 tw-flex-1">{children}</div>
          {isSelected && selectedButtons}
          {!isSelected && hoverButtons && (
            <div className="tw-invisible group-hover:tw-visible">{hoverButtons}</div>
          )}
          {dropdownContent && (isSelected || showDropdownOnHover) && (
            <div
              className={cn(
                !isSelected && showDropdownOnHover && 'tw-invisible group-hover:tw-visible',
              )}
            >
              <DropdownMenu>
                <DropdownMenuTrigger className={cn(accentColor && 'tw-me-1')} asChild>
                  <Button
                    className="tw-m-1 tw-h-6 tw-w-6"
                    variant="ghost"
                    size="icon"
                    onClick={(e) => e.stopPropagation()}
                    onFocus={(e) => e.stopPropagation()}
                  >
                    <MoreVertical />
                  </Button>
                </DropdownMenuTrigger>
                <DropdownMenuContent align="end">{dropdownContent}</DropdownMenuContent>
              </DropdownMenu>
            </div>
          )}
        </div>
        {additionalContent && (
          <div className="tw-w-fit tw-min-w-0 tw-max-w-full tw-overflow-hidden">
            {additionalContent}
          </div>
        )}
      </div>
      {accentColor && (
        <div
          className={`tw-absolute tw-right-0 tw-top-0 tw-h-full tw-w-2 tw-rounded-r-xl ${accentColor}`}
        />
      )}
    </div>
  );
}

export default ResultsCard;
